@keyframes darma-loader-uiverse-checkpoint-progress-loadingBar {
  0% {
    width: 0%;
    animation-timing-function: ease-out;
  }
  30% {
    width: 33%;
    animation-timing-function: ease-out;
  }
  60% {
    width: 66%;
    animation-timing-function: ease-out;
  }
  90% {
    width: 100%;
    animation-timing-function: ease-out;
  }
  100% {
    width: 100%;
    animation-timing-function: ease-out;
  }
}

@keyframes darma-loader-uiverse-checkpoint-progress-checkScale1 {
0% {
transform: scale(0.75);
background-color: #535353;
}
28% {
transform: scale(0.75);
background-color: #535353;
}
29% {
transform: scale(1);
background-color: rgb(0, 205, 0);
}
100% {
transform: scale(1);
background-color: rgb(0, 205, 0);
}
}

@keyframes darma-loader-uiverse-checkpoint-progress-checkScale2 {
0% {
transform: scale(0.75);
background-color: #535353;
}
58% {
transform: scale(0.75);
background-color: #535353;
}
59% {
transform: scale(1);
background-color: rgb(0, 205, 0);
}
100% {
transform: scale(1);
background-color: rgb(0, 205, 0);
}
}

@keyframes darma-loader-uiverse-checkpoint-progress-checkScale3 {
0% {
transform: scale(0.75);
background-color: #535353;
}
88% {
transform: scale(0.75);
background-color: #535353;
}
89% {
transform: scale(1);
background-color: rgb(0, 205, 0);
}
100% {
transform: scale(1);
background-color: rgb(0, 205, 0);
}
}

.darma-loader-uiverse-checkpoint-progress {
position: relative;
background-color: #535353;
border-radius: 1em;
height: 1em;
width: 330px;
}

.darma-loader-uiverse-checkpoint-progress__bar {
position: relative;
background-color: rgb(0, 205, 0);
width: 40px;
height: 100%;
border-radius: 1em;
animation: darma-loader-uiverse-checkpoint-progress-loadingBar 6s linear infinite;
}

.darma-loader-uiverse-checkpoint-progress__check-bar-container {
position: absolute;
left: 0px;
top: -4px;
z-index: 69;
display: flex;
width: 100%;
justify-content: space-between;
height: 0.5em;
}

.darma-loader-uiverse-checkpoint-progress__check {
border-radius: 1em;
height: 1.5em;
width: 1.5em;
padding: 3px;
background-color: #535353;
transform: scale(0.75);
}

.darma-loader-uiverse-checkpoint-progress__check-bar-container .darma-loader-uiverse-checkpoint-progress__check:nth-of-type(2) {
animation: darma-loader-uiverse-checkpoint-progress-checkScale1 6s linear infinite;
}
.darma-loader-uiverse-checkpoint-progress__check-bar-container .darma-loader-uiverse-checkpoint-progress__check:nth-of-type(3) {
animation: darma-loader-uiverse-checkpoint-progress-checkScale2 6s linear infinite;
}
.darma-loader-uiverse-checkpoint-progress__check-bar-container .darma-loader-uiverse-checkpoint-progress__check:nth-of-type(4) {
animation: darma-loader-uiverse-checkpoint-progress-checkScale3 6s linear infinite;
transform-origin: right;
}

